import{_ as s,o as n,c as p,a3 as e}from"./chunks/framework.B09Pga2X.js";const m=JSON.parse('{"title":"Workflows Multi-Agente","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/scenarios/workflows.md","filePath":"pt-BR/scenarios/workflows.md"}'),l={name:"pt-BR/scenarios/workflows.md"};function i(o,a,r,c,t,d){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="workflows-multi-agente" tabindex="-1">Workflows Multi-Agente <a class="header-anchor" href="#workflows-multi-agente" aria-label="Permalink to &quot;Workflows Multi-Agente&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Agentes: <code>@orchestrator</code> <code>@executor</code> <code>@planner</code> · Complexidade: Media-Alta</p></div><p>Exemplos reais de workflows mostrando como multiplos agentes coordenam para entregar funcionalidades completas.</p><h2 id="startup-mvp" tabindex="-1">Sprint MVP Startup (1 semana) <a class="header-anchor" href="#startup-mvp" aria-label="Permalink to &quot;Sprint MVP Startup (1 semana) {#startup-mvp}&quot;">​</a></h2><p><strong>Objetivo:</strong> Construir um MVP SaaS com autenticacao, dashboard e faturamento.</p><p><strong>Agentes envolvidos:</strong> <code>@planner</code> → <code>@starter</code> → <code>@orchestrator</code> → <code>@builder</code> × 3 → <code>@tester</code> → <code>@reviewer</code></p><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dia 1: Planejamento &amp; Setup</span></span>
<span class="line"><span>────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /plan Construir um MVP SaaS com auth, dashboard e billing Stripe</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @planner analisa requisitos</span></span>
<span class="line"><span>  → Produz plano COMPLEXO com 12 tarefas</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: Crie o projeto</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @starter cria o scaffold</span></span>
<span class="line"><span>  → Frontend (React/Vue) + Backend (Node.js) + Database (PostgreSQL)</span></span>
<span class="line"><span>  → Instala agentes e skills do Specialist Agent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Dia 2-3: Build Paralelo</span></span>
<span class="line"><span>─────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @orchestrator Execute o plano</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @orchestrator decompoe em 3 streams paralelos:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Stream 1: @builder (Auth)</span></span>
<span class="line"><span>  ├── Modelo de usuario + migration</span></span>
<span class="line"><span>  ├── Middleware JWT auth</span></span>
<span class="line"><span>  ├── Endpoints Login/Register</span></span>
<span class="line"><span>  └── Composable/hook de auth</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Stream 2: @builder (Dashboard)</span></span>
<span class="line"><span>  ├── Layout do dashboard</span></span>
<span class="line"><span>  ├── Service + adapter de stats</span></span>
<span class="line"><span>  ├── Componentes de graficos</span></span>
<span class="line"><span>  └── Pagina do dashboard</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Stream 3: @builder (Billing)</span></span>
<span class="line"><span>  ├── Service de integracao Stripe</span></span>
<span class="line"><span>  ├── Planos de assinatura</span></span>
<span class="line"><span>  ├── Fluxo de checkout</span></span>
<span class="line"><span>  └── Webhook handler</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Handoff: @orchestrator merge todos os streams</span></span>
<span class="line"><span>  → Roda testes de integracao</span></span>
<span class="line"><span>  → Cria checkpoint</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Dia 4: Testes &amp; Review</span></span>
<span class="line"><span>───────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @tester Criar estrategia de testes para o MVP</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @tester desenha piramide de testes:</span></span>
<span class="line"><span>  → 70% testes unitarios (services, adapters)</span></span>
<span class="line"><span>  → 20% testes de integracao (endpoints API)</span></span>
<span class="line"><span>  → 10% testes E2E (fluxo auth, fluxo checkout)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @reviewer Revisar todas as mudancas</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @reviewer executa review unificado 3-em-1:</span></span>
<span class="line"><span>  → Conformidade com Spec: PASS</span></span>
<span class="line"><span>  → Qualidade de Codigo: B+ (melhorias menores sugeridas)</span></span>
<span class="line"><span>  → Adequacao Arquitetural: PASS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Dia 5: Polish &amp; Deploy</span></span>
<span class="line"><span>───────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @devops Configurar pipeline CI/CD</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @devops cria:</span></span>
<span class="line"><span>  → Workflow GitHub Actions</span></span>
<span class="line"><span>  → Docker Compose para dev local</span></span>
<span class="line"><span>  → Config de deploy</span></span></code></pre></div><h3 id="estimativa-de-custo" tabindex="-1">Estimativa de Custo <a class="header-anchor" href="#estimativa-de-custo" aria-label="Permalink to &quot;Estimativa de Custo&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@planner:       ~3.000 tokens</span></span>
<span class="line"><span>@starter:       ~8.000 tokens</span></span>
<span class="line"><span>@orchestrator:  ~5.000 tokens</span></span>
<span class="line"><span>@builder × 3:  ~45.000 tokens</span></span>
<span class="line"><span>@tester:       ~12.000 tokens</span></span>
<span class="line"><span>@reviewer:      ~8.000 tokens</span></span>
<span class="line"><span>@devops:        ~6.000 tokens</span></span>
<span class="line"><span>─────────────────────────────</span></span>
<span class="line"><span>Total:         ~87.000 tokens (~$1,30)</span></span></code></pre></div><hr><h2 id="landing-page" tabindex="-1">Sprint Landing Page (1 dia) <a class="header-anchor" href="#landing-page" aria-label="Permalink to &quot;Sprint Landing Page (1 dia) {#landing-page}&quot;">​</a></h2><p><strong>Objetivo:</strong> Projetar e construir uma landing page completa em um dia.</p><p><strong>Agentes envolvidos:</strong> <code>@designer</code> → <code>@builder</code> × 2 → <code>@perf</code> → <code>@reviewer</code></p><h3 id="workflow-1" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-1" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Manha: Design &amp; Setup (9:00 - 11:00)</span></span>
<span class="line"><span>──────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @designer Criar um design system para nossa landing page</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @designer produz:</span></span>
<span class="line"><span>  → Paleta de cores, tipografia, tokens de espacamento</span></span>
<span class="line"><span>  → Inventario de componentes (Hero, Features, Pricing, CTA, Footer)</span></span>
<span class="line"><span>  → Breakpoints responsivos</span></span>
<span class="line"><span>  → Requisitos de acessibilidade (WCAG 2.1 AA)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Meio-dia: Build Paralelo (11:00 - 15:00)</span></span>
<span class="line"><span>──────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @orchestrator Construir as secoes da landing page em paralelo</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @orchestrator atribui:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @builder-1 (Acima da dobra):</span></span>
<span class="line"><span>  ├── Secao Hero com CTA</span></span>
<span class="line"><span>  ├── Prova social / logos</span></span>
<span class="line"><span>  └── Destaques de funcionalidades</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @builder-2 (Abaixo da dobra):</span></span>
<span class="line"><span>  ├── Grid detalhado de features</span></span>
<span class="line"><span>  ├── Tabela de precos</span></span>
<span class="line"><span>  ├── Accordion de FAQ</span></span>
<span class="line"><span>  └── Footer com links</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Handoff: Merge + verificar comportamento responsivo</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Tarde: Otimizar &amp; Entregar (15:00 - 17:00)</span></span>
<span class="line"><span>────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @perf Otimizar a landing page para Core Web Vitals</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @perf analisa:</span></span>
<span class="line"><span>  → Otimizacao de imagens (WebP, lazy loading)</span></span>
<span class="line"><span>  → Tamanho do bundle (code splitting, tree shaking)</span></span>
<span class="line"><span>  → Estrategia de carregamento de fontes (font-display: swap)</span></span>
<span class="line"><span>  → Correcoes de CLS (dimensoes explicitas)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @reviewer Review final</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @reviewer veredito: Aprovado</span></span>
<span class="line"><span>  → Performance: A (LCP &lt; 2.5s)</span></span>
<span class="line"><span>  → Acessibilidade: A (WCAG 2.1 AA compliant)</span></span>
<span class="line"><span>  → SEO: Meta tags, dados estruturados, sitemap</span></span></code></pre></div><hr><h2 id="bug-fix" tabindex="-1">Investigacao &amp; Fix de Bug (2 horas) <a class="header-anchor" href="#bug-fix" aria-label="Permalink to &quot;Investigacao &amp; Fix de Bug (2 horas) {#bug-fix}&quot;">​</a></h2><p><strong>Objetivo:</strong> Investigar um bug em producao, encontrar a causa raiz, corrigir e verificar.</p><p><strong>Agentes envolvidos:</strong> <code>@doctor</code> → <code>@debugger</code> → <code>@builder</code> → <code>@tester</code> → <code>@reviewer</code></p><h3 id="workflow-2" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-2" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fase 1: Diagnostico (30 min)</span></span>
<span class="line"><span>─────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: Usuarios reportam erros &quot;Pagamento falhou&quot; intermitentes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @doctor executa diagnostico em 4 fases:</span></span>
<span class="line"><span>  Fase 1 - Sintomas: Logs de erro mostram webhook Stripe 500s</span></span>
<span class="line"><span>  Fase 2 - Hipoteses:</span></span>
<span class="line"><span>    H1: Race condition no webhook handler</span></span>
<span class="line"><span>    H2: Chave de idempotencia nao definida</span></span>
<span class="line"><span>    H3: Timeout de transacao no banco</span></span>
<span class="line"><span>  Fase 3 - Evidencias:</span></span>
<span class="line"><span>    → Logs mostram eventos de webhook duplicados</span></span>
<span class="line"><span>    → Handler processa mesmo evento duas vezes</span></span>
<span class="line"><span>    → Segundo processamento falha em constraint unique</span></span>
<span class="line"><span>  Fase 4 - Causa Raiz: Verificacao de idempotencia ausente</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Fase 2: Correcao (30 min)</span></span>
<span class="line"><span>──────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @builder Corrigir o webhook handler</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @builder implementa:</span></span>
<span class="line"><span>  → Adicionar verificacao de chave de idempotencia</span></span>
<span class="line"><span>  → Adicionar wrapping de transacao no banco</span></span>
<span class="line"><span>  → Adicionar logging estruturado para eventos webhook</span></span>
<span class="line"><span>  → Adicionar logica de retry com backoff exponencial</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Fase 3: Verificacao (30 min)</span></span>
<span class="line"><span>─────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @tester Escrever testes para a correcao</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @tester cria:</span></span>
<span class="line"><span>  → Teste unitario: verificacao de idempotencia</span></span>
<span class="line"><span>  → Teste de integracao: tratamento de webhook duplicado</span></span>
<span class="line"><span>  → Caso edge: processamento concorrente de webhook</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /verify all</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /verify output:</span></span>
<span class="line"><span>  → Testes: 47/47 passando (3 novos)</span></span>
<span class="line"><span>  → TypeScript: 0 erros</span></span>
<span class="line"><span>  → Build: sucesso</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Fase 4: Review (30 min)</span></span>
<span class="line"><span>────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @reviewer Revisar a correcao</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @reviewer veredito: Aprovado</span></span>
<span class="line"><span>  → Seguranca: A (validacao de input adequada)</span></span>
<span class="line"><span>  → Correcao endereca causa raiz, nao sintomas</span></span>
<span class="line"><span>  → Observabilidade: logging estruturado adicionado</span></span></code></pre></div><hr><h2 id="migration" tabindex="-1">Projeto de Migracao (1-2 semanas) <a class="header-anchor" href="#migration" aria-label="Permalink to &quot;Projeto de Migracao (1-2 semanas) {#migration}&quot;">​</a></h2><p><strong>Objetivo:</strong> Migrar uma app legada Vue 2 Options API para Vue 3 Composition API.</p><p><strong>Agentes envolvidos:</strong> <code>@scout</code> → <code>@planner</code> → <code>@orchestrator</code> → <code>@migrator</code> × N → <code>@tester</code> → <code>@reviewer</code></p><h3 id="workflow-3" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-3" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Semana 1: Analise &amp; Planejamento</span></span>
<span class="line"><span>──────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @scout Analisar o codebase atual</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @scout produz inventario:</span></span>
<span class="line"><span>  → 45 componentes (38 Options API, 7 ja Composition)</span></span>
<span class="line"><span>  → 12 mixins (precisam conversao para composables)</span></span>
<span class="line"><span>  → 8 modulos Vuex (precisam migracao para Pinia)</span></span>
<span class="line"><span>  → 6 filters (precisam conversao para funcoes)</span></span>
<span class="line"><span>  → Auditoria de deps: 3 pacotes precisam alternativas Vue 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: /plan Migrar toda a app para Vue 3 Composition API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @planner produz plano COMPLEXO:</span></span>
<span class="line"><span>  → Fase 1: Infraestrutura (Vue 3, Vite, Pinia)</span></span>
<span class="line"><span>  → Fase 2: Codigo compartilhado (mixins → composables, filters)</span></span>
<span class="line"><span>  → Fase 3: Componentes (migracao em lote, 5/dia)</span></span>
<span class="line"><span>  → Fase 4: Testes (atualizar todos os testes)</span></span>
<span class="line"><span>  → Fase 5: Cleanup (remover compatibilidade Vue 2)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Semana 2: Execucao</span></span>
<span class="line"><span>───────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @orchestrator Executar o plano de migracao</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @orchestrator coordena:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Dia 1: @migrator - Migracao de infraestrutura</span></span>
<span class="line"><span>  Dia 2: @migrator × 2 - Mixins → Composables (paralelo)</span></span>
<span class="line"><span>  Dia 3-4: @migrator × 3 - Componentes (lotes de 5)</span></span>
<span class="line"><span>  Dia 5: @tester - Atualizar todos os testes</span></span>
<span class="line"><span>  Final: @reviewer - Review completo do codebase</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Template de handoff usado em cada fronteira de fase:</span></span>
<span class="line"><span>  → QA PASS / QA FAIL com evidencias</span></span>
<span class="line"><span>  → Transferencia de contexto para agente da proxima fase</span></span></code></pre></div><hr><h2 id="multi-domain" tabindex="-1">Feature Multi-Dominio (3-5 dias) <a class="header-anchor" href="#multi-domain" aria-label="Permalink to &quot;Feature Multi-Dominio (3-5 dias) {#multi-domain}&quot;">​</a></h2><p><strong>Objetivo:</strong> Adicionar um sistema de referral com frontend, backend, banco de dados e notificacoes.</p><p><strong>Agentes envolvidos:</strong> <code>@analyst</code> → <code>@planner</code> → <code>@data</code> → <code>@api</code> → <code>@orchestrator</code> → <code>@builder</code> × 2 → <code>@tester</code> → <code>@security</code> → <code>@reviewer</code></p><h3 id="workflow-4" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-4" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dia 1: Requisitos &amp; Design</span></span>
<span class="line"><span>────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @analyst Definir requisitos para um sistema de referral</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @analyst produz spec:</span></span>
<span class="line"><span>  → User stories (quem indica, indicado)</span></span>
<span class="line"><span>  → Regras de negocio (niveis de recompensa, limites)</span></span>
<span class="line"><span>  → Criterios de aceitacao por story</span></span>
<span class="line"><span>  → Casos edge (auto-referral, links expirados)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @data Projetar o schema do banco</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @data produz:</span></span>
<span class="line"><span>  → Tabela referral_codes</span></span>
<span class="line"><span>  → Tabela referral_events</span></span>
<span class="line"><span>  → Tabela reward_transactions</span></span>
<span class="line"><span>  → Indices e constraints</span></span>
<span class="line"><span>  → Script de migracao</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @api Projetar os endpoints da API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @api produz:</span></span>
<span class="line"><span>  → POST /api/referrals/generate</span></span>
<span class="line"><span>  → GET /api/referrals/:code</span></span>
<span class="line"><span>  → POST /api/referrals/redeem</span></span>
<span class="line"><span>  → GET /api/referrals/stats</span></span>
<span class="line"><span>  → Spec OpenAPI</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Dia 2-3: Build</span></span>
<span class="line"><span>───────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @orchestrator Construir o sistema de referral</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @orchestrator atribui streams paralelos:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @builder-1 (Backend):</span></span>
<span class="line"><span>  ├── Service de referral</span></span>
<span class="line"><span>  ├── Calculo de recompensa</span></span>
<span class="line"><span>  ├── Notificacoes por email</span></span>
<span class="line"><span>  └── Endpoints da API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @builder-2 (Frontend):</span></span>
<span class="line"><span>  ├── Dashboard de referrals</span></span>
<span class="line"><span>  ├── Componente de compartilhar/convidar</span></span>
<span class="line"><span>  ├── Historico de recompensas</span></span>
<span class="line"><span>  └── Handler de link de referral</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Dia 4: Seguranca &amp; Testes</span></span>
<span class="line"><span>──────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @security Auditar o sistema de referral</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @security verifica:</span></span>
<span class="line"><span>  → Rate limiting na geracao de codigos</span></span>
<span class="line"><span>  → Entropia do codigo de referral (nao adivinhavel)</span></span>
<span class="line"><span>  → Prevencao de abuso de recompensa</span></span>
<span class="line"><span>  → Validacao de input em todos os endpoints</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @tester Criar testes abrangentes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @tester cria:</span></span>
<span class="line"><span>  → Unitario: calculo de recompensa, geracao de codigo</span></span>
<span class="line"><span>  → Integracao: fluxo completo de referral</span></span>
<span class="line"><span>  → E2E: convite → cadastro → recompensa</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Dia 5: Review &amp; Entrega</span></span>
<span class="line"><span>─────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: @reviewer Revisar todo o sistema de referral</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @reviewer unificado 3-em-1:</span></span>
<span class="line"><span>  → Spec: Todas as user stories implementadas</span></span>
<span class="line"><span>  → Qualidade: A- (uma melhoria menor)</span></span>
<span class="line"><span>  → Arquitetura: Segue ARCHITECTURE.md</span></span>
<span class="line"><span>  → Veredito: Aprovado</span></span></code></pre></div><h2 id="dicas-para-workflows-multi-agente" tabindex="-1">Dicas para Workflows Multi-Agente <a class="header-anchor" href="#dicas-para-workflows-multi-agente" aria-label="Permalink to &quot;Dicas para Workflows Multi-Agente&quot;">​</a></h2><ol><li><strong>Sempre comece com <code>/plan</code></strong> - Mesmo que voce ache que sabe o escopo</li><li><strong>Use <code>@orchestrator</code> para 3+ agentes</strong> - Nao coordene manualmente</li><li><strong>Checkpoints sao obrigatorios</strong> - Cada fronteira de fase recebe um checkpoint</li><li><strong>Templates de handoff</strong> - Use handoffs estruturados entre agentes</li><li><strong>Verifique em cada fronteira</strong> - Execute <code>/verify</code> antes de passar para a proxima fase</li><li><strong>Rastreamento de custo</strong> - Use <code>/estimate</code> antes de operacoes caras</li></ol>`,36)])])}const g=s(l,[["render",i]]);export{m as __pageData,g as default};
